const inJson = $input.first().json;
const body = inJson.body || inJson;
const table = body.table;
const r = body.record || {};
const COMPANY='tblnj3YlOI3thjrXp', CONTACT='tblWJksRL1yKSUgrm';
let airtableTable, fields, matchOn='Supabase ID';
if (table === 'companies') {
  airtableTable = COMPANY;
  fields = { 'Supabase ID': r.id, 'Company Name': r.name, 'Domain': r.domain, 'Industry': r.industry, 'HQ Country': r.country };
} else if (table === 'contacts') {
  airtableTable = CONTACT;
  fields = { 'Supabase ID': r.id, 'Full Name': r.full_name, 'First Name': r.first_name, 'Last Name': r.last_name,
    'Email': r.email, 'Title': r.title, 'Company Name': r.company_name, 'Company Domain': r.company_domain,
    'LinkedIn URL': r.linkedin_url, 'City': r.city, 'State/Region': r.state_region, 'Country': r.country };
} else {
  return [{ json: { skip: true, reason: 'unknown table ' + table } }];
}
Object.keys(fields).forEach(k => { if (fields[k] == null || fields[k] === '') delete fields[k]; });
return [{ json: { airtableTable, airtableBody: { performUpsert: { fieldsToMergeOn: [matchOn] }, records: [{ fields }], typecast: true } } }];
